const file = $input.item.json;

// Derive matter ID from folder name or file naming convention
// Convention: [MATTER-ID]_DocumentName.pdf e.g. DD-2026-001_SPA_Draft.pdf
const fileNameMatch = file.name?.match(/^([A-Z]{2}-\d{4}-\d{3})_(.+)$/);
const matterId = fileNameMatch?.[1] || 'DD-' + new Date().getFullYear() + '-' + Math.floor(Math.random() * 999).toString().padStart(3, '0');
const cleanName = fileNameMatch?.[2]?.replace(/\.[^.]+$/, '') || file.name?.replace(/\.[^.]+$/, '');

return {
  json: {
    fileId: file.id,
    fileName: file.name,
    cleanDocName: cleanName,
    matterId,
    mimeType: file.mimeType || 'application/pdf',
    fileSize: file.size,
    uploadedAt: file.createdTime || new Date().toISOString(),
    processedAt: new Date().toISOString()
  }
};

const raw = $input.item.json.content?.[0]?.text || '{}';
const meta = $('Extract DD Session Metadata').item.json;
let analysis;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  analysis = match ? JSON.parse(match[0]) : {};
} catch(e) {
  analysis = { documentType: 'Other', documentSummary: 'Parse error — manual review required', partiesIdentified: [], keyDates: [], keyFinancialTerms: [], redFlags: [{ severity: 'HIGH', clause: 'Parse Error', issue: 'Could not parse AI analysis — manual review essential', recommendation: 'Review document manually' }], missingProvisions: [], favourableTerms: [], overallRiskRating: 'HIGH', riskRatingSummary: 'Auto-analysis failed', immediateActions: ['Review document manually'] };
}

const criticalFlags = (analysis.redFlags || []).filter(f => f.severity === 'CRITICAL').length;
const highFlags = (analysis.redFlags || []).filter(f => f.severity === 'HIGH').length;

return {
  json: {
    matterId: meta.matterId,
    fileId: meta.fileId,
    fileName: meta.fileName,
    cleanDocName: meta.cleanDocName,
    processedAt: meta.processedAt,
    documentType: analysis.documentType || 'Other',
    documentSummary: analysis.documentSummary || '',
    partiesIdentified: analysis.partiesIdentified || [],
    keyDates: analysis.keyDates || [],
    keyFinancialTerms: analysis.keyFinancialTerms || [],
    redFlags: analysis.redFlags || [],
    missingProvisions: analysis.missingProvisions || [],
    favourableTerms: analysis.favourableTerms || [],
    ipConsiderations: analysis.ipConsiderations || 'None',
    employmentObligations: analysis.employmentObligations || 'None',
    regulatoryIssues: analysis.regulatoryIssues || 'None',
    overallRiskRating: analysis.overallRiskRating || 'MEDIUM',
    riskRatingSummary: analysis.riskRatingSummary || '',
    immediateActions: analysis.immediateActions || [],
    criticalFlagCount: criticalFlags,
    highFlagCount: highFlags,
    totalFlagCount: (analysis.redFlags || []).length
  }
};
